import os
import pickle
import joblib
import boto3
import json
from google.cloud import storage as gcs_storage
from azure.storage.blob import BlobServiceClient
import tempfile
import shutil
from pathlib import Path

class ModelLoader:
    def __init__(self):
        self.model_path = os.environ.get('MODEL_PATH', '')
        self.model = None
        self.cloud_provider = self._detect_cloud_provider()
        
    def _detect_cloud_provider(self):
        if self.model_path.startswith('s3://'):
            return 'aws'
        elif self.model_path.startswith('gs://'):
            return 'gcp'
        elif self.model_path.startswith('https://') and 'blob.core.windows.net' in self.model_path:
            return 'azure'
        else:
            return 'local'
    
    def _download_from_s3(self, bucket, key, local_path):
        s3_client = boto3.client('s3')
        s3_client.download_file(bucket, key, local_path)
    
    def _download_from_gcs(self, bucket_name, blob_name, local_path):
        client = gcs_storage.Client()
        bucket = client.bucket(bucket_name)
        blob = bucket.blob(blob_name)
        blob.download_to_filename(local_path)
    
    def _download_from_azure(self, connection_string, container, blob_name, local_path):
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        blob_client = blob_service_client.get_blob_client(container=container, blob=blob_name)
        with open(local_path, 'wb') as f:
            f.write(blob_client.download_blob().readall())
    
    def _get_latest_version_s3(self, bucket, prefix):
        s3_client = boto3.client('s3')
        response = s3_client.list_objects_v2(Bucket=bucket, Prefix=prefix)
        
        if 'Contents' not in response:
            return None
        
        objects = response['Contents']
        objects.sort(key=lambda x: x['LastModified'], reverse=True)
        return objects[0]['Key']
    
    def _get_latest_version_gcs(self, bucket_name, prefix):
        client = gcs_storage.Client()
        bucket = client.bucket(bucket_name)
        blobs = list(bucket.list_blobs(prefix=prefix))
        
        if not blobs:
            return None
        
        blobs.sort(key=lambda x: x.updated, reverse=True)
        return blobs[0].name
    
    def _get_latest_version_azure(self, connection_string, container, prefix):
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        container_client = blob_service_client.get_container_client(container)
        blobs = list(container_client.list_blobs(name_starts_with=prefix))
        
        if not blobs:
            return None
        
        blobs.sort(key=lambda x: x.last_modified, reverse=True)
        return blobs[0].name
    
    def download_model(self):
        temp_dir = tempfile.mkdtemp()
        local_model_path = os.path.join(temp_dir, 'model')
        
        if self.cloud_provider == 'aws':
            path_parts = self.model_path.replace('s3://', '').split('/', 1)
            bucket = path_parts[0]
            prefix = path_parts[1] if len(path_parts) > 1 else ''
            
            latest_key = self._get_latest_version_s3(bucket, prefix)
            if not latest_key:
                latest_key = prefix
            
            self._download_from_s3(bucket, latest_key, local_model_path)
            
        elif self.cloud_provider == 'gcp':
            path_parts = self.model_path.replace('gs://', '').split('/', 1)
            bucket_name = path_parts[0]
            prefix = path_parts[1] if len(path_parts) > 1 else ''
            
            latest_blob = self._get_latest_version_gcs(bucket_name, prefix)
            if not latest_blob:
                latest_blob = prefix
            
            self._download_from_gcs(bucket_name, latest_blob, local_model_path)
            
        elif self.cloud_provider == 'azure':
            connection_string = os.environ.get('AZURE_STORAGE_CONNECTION_STRING', '')
            container = os.environ.get('AZURE_CONTAINER', '')
            blob_prefix = os.environ.get('AZURE_BLOB_PREFIX', '')
            
            latest_blob = self._get_latest_version_azure(connection_string, container, blob_prefix)
            if not latest_blob:
                latest_blob = blob_prefix
            
            self._download_from_azure(connection_string, container, latest_blob, local_model_path)
            
        else:
            if os.path.isdir(self.model_path):
                files = sorted(Path(self.model_path).glob('*'), key=os.path.getmtime, reverse=True)
                if files:
                    shutil.copy(str(files[0]), local_model_path)
            else:
                shutil.copy(self.model_path, local_model_path)
        
        return local_model_path
    
    def load_model(self):
        local_path = self.download_model()
        
        try:
            with open(local_path, 'rb') as f:
                self.model = pickle.load(f)
        except:
            try:
                self.model = joblib.load(local_path)
            except:
                import torch
                self.model = torch.load(local_path)
        
        return self.model
    
    def predict(self, input_data):
        if self.model is None:
            raise ValueError("Model not loaded")
        
        if hasattr(self.model, 'predict'):
            return self.model.predict(input_data)
        elif hasattr(self.model, 'forward'):
            return self.model.forward(input_data)
        else:
            return self.model(input_data)


class InferenceService:
    def __init__(self):
        self.loader = ModelLoader()
        self.model = None
        
    def startup(self):
        print(f"Loading model from: {self.loader.model_path}")
        self.model = self.loader.load_model()
        print("Model loaded successfully")
        
    def serve(self, input_data):
        return self.loader.predict(input_data)


if __name__ == '__main__':
    service = InferenceService()
    service.startup()
    
    print("Inference service ready")